-- ============================================================
-- 0625 — populate exercise common_mistakes (EN + ES)
-- ============================================================
-- Fills the columns added in 0624 with 2-3 movement-specific form mistakes each,
-- bilingual. Powers the "common mistakes" section of the equipment-QR feature.
-- ============================================================

UPDATE exercises AS e SET common_mistakes = v.en, common_mistakes_es = v.es
FROM (VALUES
  ('ex_bp', ARRAY['Bouncing the bar off the chest','Flaring elbows out to 90°','Lifting hips off the bench'], ARRAY['Rebotar la barra en el pecho','Abrir los codos a 90°','Despegar la cadera del banco']),
  ('ex_ibp', ARRAY['Bench too steep, turns into a shoulder press','Bar drifting up toward the neck','Flaring elbows too wide'], ARRAY['Banco muy inclinado, se vuelve press de hombro','La barra sube hacia el cuello','Abrir demasiado los codos']),
  ('ex_dcbp', ARRAY['Lowering the bar toward the face','Legs not locked in, sliding down','Bouncing the bar off the chest'], ARRAY['Bajar la barra hacia la cara','Piernas sueltas y resbalar','Rebotar la barra en el pecho']),
